def speed_flag(psv):
    try:
        v = float(psv)
        if v >= 32:   return "⚡ ELITE"
        elif v >= 31: return "🔵 HIGH"
        elif v >= 30: return "🟡 FAST"
        elif v >= 29: return "🟠 MEDIUM"
        else:         return "—"
    except:
        return "—"

def ifi_label(pct):
    """pct is 0-100"""
    try:
        p = float(pct)
        if p >= 90:  return "ELITE"
        elif p >= 75: return "STRONG"
        elif p >= 50: return "AVERAGE"
        elif p >= 25: return "BELOW"
        else:         return "WEAK"
    except:
        return "—"

